import org.apache.commons.logging.Log;
  import org.apache.commons.logging.LogFactory;
  import sailpoint.connector.DelimitedFileConnector;
  import sailpoint.tools.Util;

  Log logger = LogFactory.getLog("Ascension-Rule-BuildMap-Morrisey");

  logger.debug("Entering Ascension-Rule-BuildMap-Morrisey"); 

  Map map = DelimitedFileConnector.defaultBuildMap(cols,record);

  String status = (String) map.get("Status");

  if(Util.nullSafeCaseInsensitiveEq("Active",status) || Util.nullSafeCaseInsensitiveEq("Applicant",status)){
    map.put("IIQDisabled","false");
  } else{
    map.put("IIQDisabled","true");
  }

  String facContact = (String) map.get("FacContact");

  if(Util.isNotNullOrEmpty(facContact)){
    Map managerMorriseyMap = state.get("managerMorriseyMap");
    if(managerMorriseyMap == null){
      logger.debug("managerMorriseyMap is null, hence populate it from DB");
      managerMorriseyMap = getManagerMapFromDB();
      state.put("managerMorriseyMap",managerMorriseyMap);
      managerMorriseyMap = state.get("managerMorriseyMap");
      logger.debug("managerMorriseyMap fetched :: ");
    }


    if(managerMorriseyMap!=null && managerMorriseyMap.get(facContact)!=null ){
      map.put("ManagerID",managerMorriseyMap.get(facContact));
    }else{
      map = new HashMap();
    }
  }else{
  	map =  new HashMap();
  }


  return map;
